const items = $input.all();

return items.map((item) => {
  const data = item.json;
  const url = data.soundcloud_link || '';
  const audit_flags = [];
  const audit_messages = [];

  if (!url.includes('soundcloud.com')) {
    audit_flags.push('NOT_SOUNDCLOUD_LINK');
    audit_messages.push('Your link must be a valid SoundCloud URL.');
  } else if (!url.includes('/s-')) {
    audit_flags.push('PUBLIC_LINK_WARNING');
    audit_messages.push(
      'Your SoundCloud link appears public. Private demo links (with /s-) are preferred for unreleased tracks.',
    );
  }

  if (!data.reference_artists || data.reference_artists.length === 0) {
    audit_flags.push('MISSING_REFERENCE_ARTISTS');
    audit_messages.push('Please provide at least one reference artist.');
  }

  const blocking = ['NOT_SOUNDCLOUD_LINK', 'MISSING_REFERENCE_ARTISTS'];
  const is_valid_for_research = !audit_flags.some((flag) => blocking.includes(flag));

  return {
    json: {
      ...data,
      audit_flags,
      audit_messages,
      is_valid_for_research,
      soundcloud_downloadable: null,
      soundcloud_track: null,
      phase: 'phase-01-preflight',
    },
  };
});

const base = $('Pre-Flight Rules').first().json;
const resolve = $input.first().json || {};
const audit_flags = [...(base.audit_flags || [])];
const audit_messages = [...(base.audit_messages || [])];
const clientId = ($env.SOUNDCLOUD_CLIENT_ID || '').trim();

let soundcloud_downloadable = null;
let soundcloud_track = null;

if (!clientId) {
  if (!audit_flags.includes('DOWNLOAD_CHECK_SKIPPED')) {
    audit_flags.push('DOWNLOAD_CHECK_SKIPPED');
    audit_messages.push(
      'Download status could not be verified automatically. Enable downloads on your SoundCloud track so A&Rs can grab your demo.',
    );
  }
} else if (resolve.error || resolve.statusCode >= 400 || resolve.code) {
  if (!audit_flags.includes('DOWNLOAD_CHECK_FAILED')) {
    audit_flags.push('DOWNLOAD_CHECK_FAILED');
    audit_messages.push(
      'We could not verify whether your track is downloadable. Please confirm downloads are enabled in SoundCloud track settings.',
    );
  }
} else if (typeof resolve.downloadable === 'boolean') {
  soundcloud_downloadable = resolve.downloadable;
  soundcloud_track = {
    id: resolve.id || null,
    title: resolve.title || null,
    permalink: resolve.permalink_url || null,
  };

  if (!resolve.downloadable) {
    audit_flags.push('DOWNLOAD_NOT_ENABLED');
    audit_messages.push(
      'Your track does not appear to be downloadable. A&Rs often need a download button — enable it in SoundCloud track settings.',
    );
  }
}

const blocking = ['NOT_SOUNDCLOUD_LINK', 'MISSING_REFERENCE_ARTISTS'];
const is_valid_for_research = !audit_flags.some((flag) => blocking.includes(flag));

return [
  {
    json: {
      ...base,
      audit_flags,
      audit_messages,
      is_valid_for_research,
      soundcloud_downloadable,
      soundcloud_track,
      phase: 'phase-01-preflight',
    },
  },
];
